// Inputs from webhook body (Flask sends message + products)
const body     = $('Webhook').first().json.body || {};
const question = (body.message || body.question || '').trim();
const products = Array.isArray(body.products) ? body.products : [];

const count = products.length;
const q     = question.toLowerCase();
let reply   = '';

// Intent: count / total
if (!q || q.includes('how many') || q.includes('count') || q.includes('total') || q.includes('number of')) {
  reply = `We currently have ${count} product${count !== 1 ? 's' : ''} registered in the catalog.`;

// Intent: list / show all
} else if (q.includes('list') || q.includes('show') || q.includes('all product') || q.includes('catalog')) {
  if (count === 0) {
    reply = 'The product catalog is currently empty.';
  } else {
    const lines = products
      .map(p => `• ${p.name} — $${parseFloat(p.price).toFixed(2)} (qty: ${p.quantity})`)
      .join('\n');
    reply = `Here are all ${count} products in the catalog:\n\n${lines}`;
  }

// Intent: price / expensive / cheap
} else if (q.includes('price') || q.includes('expensive') || q.includes('cheap') || q.includes('cost')) {
  if (count === 0) {
    reply = 'The catalog is empty — no pricing data available yet.';
  } else {
    const sorted = [...products].sort((a, b) => b.price - a.price);
    const top    = sorted.slice(0, 5);
    const lines  = top.map(p => `• ${p.name}: $${parseFloat(p.price).toFixed(2)}`).join('\n');
    reply = `Top ${top.length} most expensive product${top.length !== 1 ? 's' : ''}:\n\n${lines}`;
  }

// Intent: stock / inventory / quantity
} else if (q.includes('stock') || q.includes('inventory') || q.includes('quantity') || q.includes('low')) {
  const lowStock = products.filter(p => p.quantity < 10);
  if (lowStock.length === 0) {
    reply = `All ${count} products are well-stocked (10+ units each).`;
  } else {
    const lines = lowStock
      .map(p => `• ${p.name}: ${p.quantity} unit${p.quantity !== 1 ? 's' : ''} remaining`)
      .join('\n');
    reply = `${lowStock.length} product${lowStock.length > 1 ? 's are' : ' is'} running low:\n\n${lines}`;
  }

// Intent: search by name
} else if (q.includes('find') || q.includes('search') || q.includes('look for')) {
  const term  = q.replace(/(find|search|look for)/g, '').trim();
  const found = products.filter(p => p.name.toLowerCase().includes(term));
  if (found.length === 0) {
    reply = `No products matching "${term}" were found.`;
  } else {
    const lines = found
      .map(p => `• ${p.name} — $${parseFloat(p.price).toFixed(2)} (qty: ${p.quantity})`)
      .join('\n');
    reply = `Found ${found.length} matching product${found.length !== 1 ? 's' : ''}:\n\n${lines}`;
  }

// Fallback
} else {
  reply = `I'm your product catalog assistant! We have ${count} product${count !== 1 ? 's' : ''} in stock.\n\nTry asking:\n• "How many products do we have?"\n• "List all products"\n• "Which products are low on stock?"\n• "Show the most expensive products"\n• "Find wireless"`;
}

return [{ json: { reply, total_products: count } }];
